arguments.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup so it's ready for predictions
var loggerFactory = LoggerFactory.Create(b => b.AddConsole());
var trainer = new ModelTrainingService(loggerFactory.CreateLogger<ModelTrainingService>());
trainer.TrainAndEvaluate();

// Register label configuration and prediction engine pool
builder.Services.AddSingleton(new LabelConfiguration { Labels = trainer.Labels });
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

